args.sparql:
SELECT ?enzyme ?enzymeLabel WHERE {
  wd:Q133895 wdt:P353 ?enzyme.
  ?enzyme rdfs:label ?enzymeLabel.
  FILTER(LANG(?enzymeLabel) = "en").
}

SELECT ?enzyme ?enzymeLabel WHERE {
  ?enzyme wdt:P682 wd:Q133895.
  ?enzyme rdfs:label ?enzymeLabel.
  FILTER(LANG(?enzymeLabel) = "en").
}

SELECT DISTINCT ?enzyme ?enzymeLabel WHERE {
  ?enzyme wdt:P682 wd:Q133895;
          rdfs:label ?enzymeLabel.
  FILTER(LANG(?enzymeLabel) = "en").
} ORDER BY ?enzymeLabel
